package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetQuantity() throws Exception {
    // Using constructor to set quantity
    com.google.gson.examples.android.model.LineItem lineItem = new com.google.gson.examples.android.model.LineItem("TestItem", 5, 123456L, "USD");
    assertEquals(5, lineItem.getQuantity());

    // Using reflection to invoke getQuantity (even if public, per instructions)
    int quantity = (int) com.google.gson.examples.android.model.LineItem.class.getDeclaredMethod("getQuantity").invoke(lineItem);
    assertEquals(5, quantity);
  }
}
